SELECT COUNT(*) AS resolved_count
  FROM alert_history
  WHERE action_taken = 'Resolved';

SELECT COUNT(alert_id) AS malware_alert_count
FROM alert_tags
WHERE tag_name = 'Malware';

SELECT provider_name
FROM providers
WHERE provider_id IN (SELECT provider_id FROM alerts);

SELECT severity_id, count
FROM alert_severity_tracking
WHERE timestamp = '2023-05-01 00:00:00';

SELECT alert_name, alert_status
FROM alerts
WHERE severity_id = (SELECT severity_id FROM severity_levels WHERE severity_name = 'High');
